#define THREADS 256

inline int mirror_index_1d(int d, int size)
{
    if (size <= 1) return 0;
    if (d >= size) {
        d = 2 * size - 2 - d;
    } else if (d < 0) {
        d = -d;
    }
    if (d < 0) d = 0;
    if (d >= size) d = size - 1;
    return d;
}

inline int src_at(__global const int *in, int sx, int sy, int x, int y)
{
    const int mx = mirror_index_1d(x, sx);
    const int my = mirror_index_1d(y, sy);
    return in[my * sx + mx];
}

inline int h53_high_from_odd(__global const int *in, int sx, int sy, int row, int oddx)
{
    row = mirror_index_1d(row, sy);
    oddx = mirror_index_1d(oddx, sx);

    const int l = mirror_index_1d(oddx - 1, sx);
    const int r = mirror_index_1d(oddx + 1, sx);

    const int c = src_at(in, sx, sy, oddx, row);
    const int p = src_at(in, sx, sy, l, row);
    const int n = src_at(in, sx, sy, r, row);

    return c - ((p + n) / 2);
}

inline int h53_low_from_even(__global const int *in, int sx, int sy, int row, int evenx)
{
    row = mirror_index_1d(row, sy);
    evenx = mirror_index_1d(evenx, sx);

    const int lo = mirror_index_1d(evenx - 1, sx);
    const int ro = mirror_index_1d(evenx + 1, sx);

    const int hleft  = h53_high_from_odd(in, sx, sy, row, lo);
    const int hright = h53_high_from_odd(in, sx, sy, row, ro);
    const int c      = src_at(in, sx, sy, evenx, row);

    return c + ((hleft + hright + 2) / 4);
}

inline int band_low_row(__global const int *in, int sx, int sy, int row, int lx)
{
    return h53_low_from_even(in, sx, sy, row, 2 * lx);
}

inline int band_high_row(__global const int *in, int sx, int sy, int row, int hx)
{
    return h53_high_from_odd(in, sx, sy, row, 2 * hx + 1);
}

inline int v53_high_from_lowband(__global const int *in, int sx, int sy, int oddy, int lx)
{
    oddy = mirror_index_1d(oddy, sy);

    const int pRow = mirror_index_1d(oddy - 1, sy);
    const int nRow = mirror_index_1d(oddy + 1, sy);

    const int c = band_low_row(in, sx, sy, oddy, lx);
    const int p = band_low_row(in, sx, sy, pRow, lx);
    const int n = band_low_row(in, sx, sy, nRow, lx);

    return c - ((p + n) / 2);
}

inline int v53_low_from_lowband(__global const int *in, int sx, int sy, int eveny, int lx)
{
    eveny = mirror_index_1d(eveny, sy);

    const int pOdd = mirror_index_1d(eveny - 1, sy);
    const int nOdd = mirror_index_1d(eveny + 1, sy);

    const int c = band_low_row(in, sx, sy, eveny, lx);
    const int p = v53_high_from_lowband(in, sx, sy, pOdd, lx);
    const int n = v53_high_from_lowband(in, sx, sy, nOdd, lx);

    return c + ((p + n + 2) / 4);
}

inline int v53_high_from_highband(__global const int *in, int sx, int sy, int oddy, int hx)
{
    oddy = mirror_index_1d(oddy, sy);

    const int pRow = mirror_index_1d(oddy - 1, sy);
    const int nRow = mirror_index_1d(oddy + 1, sy);

    const int c = band_high_row(in, sx, sy, oddy, hx);
    const int p = band_high_row(in, sx, sy, pRow, hx);
    const int n = band_high_row(in, sx, sy, nRow, hx);

    return c - ((p + n) / 2);
}

inline int v53_low_from_highband(__global const int *in, int sx, int sy, int eveny, int hx)
{
    eveny = mirror_index_1d(eveny, sy);

    const int pOdd = mirror_index_1d(eveny - 1, sy);
    const int nOdd = mirror_index_1d(eveny + 1, sy);

    const int c = band_high_row(in, sx, sy, eveny, hx);
    const int p = v53_high_from_highband(in, sx, sy, pOdd, hx);
    const int n = v53_high_from_highband(in, sx, sy, nOdd, hx);

    return c + ((p + n + 2) / 4);
}

__kernel void c_CopySrcToComponents(__global int *d_r,
                                    __global int *d_g,
                                    __global int *d_b,
                                    __global const uchar *d_src,
                                    const int pixels)
{
    const int gid = (int)get_global_id(0);

    if (gid < pixels) {
        const int base = gid * 3;
        d_r[gid] = (int)d_src[base + 0] - 128;
        d_g[gid] = (int)d_src[base + 1] - 128;
        d_b[gid] = (int)d_src[base + 2] - 128;
    }
}

__kernel void c_CopySrcToComponent(__global int *d_c,
                                   __global const uchar *d_src,
                                   const int pixels)
{
    const int gid = (int)get_global_id(0);

    if (gid < pixels) {
        d_c[gid] = (int)d_src[gid] - 128;
    }
}

__kernel void cl_fdwt53Kernel(__global const int *input,
                              __global int *output,
                              const int sizeX,
                              const int sizeY,
                              const int winSteps,
                              const int WIN_SX,
                              const int WIN_SY)
{
    (void)winSteps;
    (void)WIN_SX;
    (void)WIN_SY;

    const int llSizeX = (sizeX + 1) / 2;
    const int llSizeY = (sizeY + 1) / 2;
    const int hlSizeX = sizeX - llSizeX;
    const int lhSizeY = sizeY - llSizeY;

    const int sizeLL = llSizeX * llSizeY;
    const int sizeHL = hlSizeX * llSizeY;
    const int sizeLH = llSizeX * lhSizeY;
    const int total  = sizeX * sizeY;

    const int gid0 = (int)get_global_id(0);
    const int gid1 = (int)get_global_id(1);
    const int gsz0 = (int)get_global_size(0);
    const int gsz1 = (int)get_global_size(1);
    const int tid  = gid1 * gsz0 + gid0;
    const int tnum = gsz0 * gsz1;

    for (int idx = tid; idx < total; idx += tnum) {
        if (idx < sizeLL) {
            const int x = idx % llSizeX;
            const int y = idx / llSizeX;
            output[idx] = v53_low_from_lowband(input, sizeX, sizeY, 2 * y, x);
        } else if (idx < sizeLL + sizeHL) {
            const int off = idx - sizeLL;
            const int x = off % hlSizeX;
            const int y = off / hlSizeX;
            output[idx] = v53_low_from_highband(input, sizeX, sizeY, 2 * y, x);
        } else if (idx < sizeLL + sizeHL + sizeLH) {
            const int off = idx - sizeLL - sizeHL;
            const int x = off % llSizeX;
            const int y = off / llSizeX;
            output[idx] = v53_high_from_lowband(input, sizeX, sizeY, 2 * y + 1, x);
        } else {
            const int off = idx - sizeLL - sizeHL - sizeLH;
            const int x = off % hlSizeX;
            const int y = off / hlSizeX;
            output[idx] = v53_high_from_highband(input, sizeX, sizeY, 2 * y + 1, x);
        }
    }
}
